function parseCSVLine(line) {
  const cells = [];
  let cur = '', inQuote = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuote && line[i+1] === '"') { cur += '"'; i++; }
      else inQuote = !inQuote;
    } else if (ch === ',' && !inQuote) {
      cells.push(cur); cur = '';
    } else {
      cur += ch;
    }
  }
  cells.push(cur);
  return cells.map(c => c.trim());
}

const lines = input.trim().split('\n').filter(Boolean);
const rows = lines.map(parseCSVLine);
const colCount = Math.max(...rows.map(r => r.length));
// Pad rows
for (const r of rows) while (r.length < colCount) r.push('');
// Compute column widths
const widths = Array.from({ length: colCount }, (_, i) =>
  Math.max(3, ...rows.map(r => r[i].length))
);
const sep = '|' + widths.map(w => '-'.repeat(w + 2)).join('|') + '|';
const format = row => '| ' + row.map((c, i) => c.padEnd(widths[i])).join(' | ') + ' |';
const [header, ...body] = rows;
const out = [format(header), sep, ...body.map(format)].join('\n');
return { output: out, outputLanguage: 'markdown' };
